function defineNextConfig(config) {
  return config;
}

export default defineNextConfig({
  reactStrictMode: true,
  swcMinify: true,
});
```

**Pattern:** The config imports server environment validation, ensuring invalid env vars prevent build.

---

## 4. ENVIRONMENT CONFIGURATION SYSTEM

### Base Schema (`template/base/src/env/schema.mjs`)
```javascript
