## 8. TRPC SETUP PATTERNS

### Prisma Client (`template/addons/prisma/client.ts`)
**File location:** `src/server/db/client.ts`

```typescript
import { PrismaClient } from "@prisma/client";
import { env } from "../../env/server.mjs";

declare global {
  var prisma: PrismaClient | undefined;
}

export const prisma =
  global.prisma ||
  new PrismaClient({
    log: ["query"],
  });

if (env.NODE_ENV !== "production") {
  global.prisma = prisma;
}
```

**Pattern:** Uses global singleton pattern to avoid creating multiple PrismaClient instances in development.

### tRPC Context - Base (`template/addons/trpc/base-context.ts`)
**File location:** `src/server/router/context.ts`

```typescript
import * as trpc from "@trpc/server";
import * as trpcNext from "@trpc/server/adapters/next";

export const createContext = (opts?: trpcNext.CreateNextContextOptions) => {
  const req = opts?.req;
  const res = opts?.res;

  return { req, res };
};

type Context = trpc.inferAsyncReturnType<typeof createContext>;

export const createRouter = () => trpc.router<Context>();
```

### tRPC Context with Auth (`template/addons/trpc/auth-context.ts`)
```typescript
import * as trpc from "@trpc/server";
import * as trpcNext from "@trpc/server/adapters/next";
import { unstable_getServerSession as getServerSession } from "next-auth";
import { authOptions as nextAuthOptions } from "../../pages/api/auth/[...nextauth]";

export const createContext = async (opts?: trpcNext.CreateNextContextOptions) => {
  const req = opts?.req;
  const res = opts?.res;
  const session = req && res && (await getServerSession(req, res, nextAuthOptions));

  return { req, res, session };
};

type Context = trpc.inferAsyncReturnType<typeof createContext>;

export const createRouter = () => trpc.router<Context>();
```

