  logNextSteps({ projectName: appDir, packages: usePackages, noInstall });
  const pkgJson = (await fs.readJSON(
    path.join(projectDir, "package.json"),
  )) as CT3APackageJSON;
  pkgJson.name = scopedAppName;
  pkgJson.ct3aMetadata = { initVersion: getVersion() };

